USE crs_system;

SET @studentEmailExists := (SELECT COUNT(*) FROM information_schema.columns WHERE table_schema = DATABASE() AND table_name = 'students' AND column_name = 'email');
SET @studentEmailSql := IF(@studentEmailExists = 0, 'ALTER TABLE students ADD COLUMN email VARCHAR(100) NULL AFTER programme', 'SELECT 1');
PREPARE stmt FROM @studentEmailSql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

SET @courseInstructorExists := (SELECT COUNT(*) FROM information_schema.columns WHERE table_schema = DATABASE() AND table_name = 'courses' AND column_name = 'instructor');
SET @courseInstructorSql := IF(@courseInstructorExists = 0, 'ALTER TABLE courses ADD COLUMN instructor VARCHAR(100) NULL AFTER credit_hours', 'SELECT 1');
PREPARE stmt FROM @courseInstructorSql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

SET @courseCodeUniqueExists := (SELECT COUNT(*) FROM information_schema.statistics WHERE table_schema = DATABASE() AND table_name = 'courses' AND column_name = 'course_code' AND non_unique = 0);
SET @courseCodeUniqueSql := IF(@courseCodeUniqueExists = 0, 'ALTER TABLE courses ADD CONSTRAINT uk_courses_course_code UNIQUE (course_code)', 'SELECT 1');
PREPARE stmt FROM @courseCodeUniqueSql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;


